    {
      ArrayList colors = new ArrayList();
      colors.Add(Color.FromArgb(90, 123, 100, 90));
      colors.Add(Color.FromArgb(90, 123, 140, 90));
      colors.Add(Color.FromArgb(90, 123, 100, 190));
      colors.Add(Color.FromArgb(90, 23, 100, 90));
      colors.Add(Color.FromArgb(90, 123, 0, 90));
      colors.Add(Color.FromArgb(90, 123, 100, 0));
      m_panelDrawing.Colors = (Color[])colors.ToArray(typeof(Color));
    }

